# ═══════════════════════════════════════════════════════
# SAFE HTTP SESSION — prevents "Unclosed connection" warnings
# ═══════════════════════════════════════════════════════
# aiohttp SSL transports need one event-loop tick after session.close()
# to fully release. Without it, GC triggers "Unclosed connection".

@asynccontextmanager
async def _safe_http(**kwargs):
    """One-off aiohttp session with proper SSL transport cleanup."""
    session = aiohttp.ClientSession(**kwargs)
    try:
        yield session
    finally:
        await session.close()
        await asyncio.sleep(0)


# ═══════════════════════════════════════════════════════
# GENDER DETECTION — local copy to avoid fragile cross-module import
# ═══════════════════════════════════════════════════════

def _detect_agent_is_female(name: str = '', explicit_gender: str = '') -> bool:
    """Определяет род агента. Приоритет — явный пол из БД (explicit_gender).
    Если explicit_gender не задан или содержит неопределённое значение —
    определяет по окончанию имени (name-based fallback).
    """
    if explicit_gender:
        g = explicit_gender.strip().lower()
        if g in ('female', 'женский', 'жен'):
            return True
        if g in ('male', 'мужской', 'муж'):
            return False
    # Name-based fallback: русские женские имена оканчиваются на а/я
    if name:
        _name_clean = name.strip()
        if _name_clean and _name_clean[-1] in 'аяАЯ' and _name_clean[-2:].lower() not in ('ша', 'жа'):
            return True
    return False


# ═══════════════════════════════════════════════════════
# USER-LEVEL CHANNEL ENRICHMENT
# ═══════════════════════════════════════════════════════
# Добавляет каналы пользователя (Discord, Telegram) к agent_caps.
# Эти каналы хранятся на уровне users, а не user_agents,
# поэтому _parse_agent_integrations() их не видит.

def _enrich_caps_with_user_channels(caps: list, user=None) -> list:
    """Дополняет список интеграций агента user-level каналами.
    
    Для добавления нового канала: добавить поле в models.User + строку ниже.
    """
    if not user:
        return caps
    enriched = set(caps)
    # (атрибут модели User, label для интеграции)
    _USER_CHANNELS = [
        ('discord_webhook', 'Discord (канал пользователя)'),
        ('telegram_channel', 'Telegram-канал (канал пользователя)'),
    ]
    for attr, label in _USER_CHANNELS:
        if getattr(user, attr, None):
            enriched.add(label)
    return sorted(enriched)


