        (('пост', 'контент', 'публикац', 'статья', 'статей'), 'posts', 30, 'публикаций'),
        (('просмотр', 'охват', 'view', 'impression', 'читател'), 'views', 1000, 'просмотров'),
        (('подписчик', 'follower'), 'subscribers', 200, 'подписчиков'),
