        (('вакансия', 'кандидат', 'найм', 'нанять', 'рекрутинг', 'резюме'), 'contacts', 10, 'кандидатов'),
        (('стартап', 'startup', 'mvp', 'питч', 'акселератор', 'запустить продукт'), 'tasks', 30, 'этапов'),
