                _tc: dict = {}
                for _h_al in _hist_al:
                    _tm_al = _re_al.search(r'\[([^\]]+)\]', _h_al)
                    if _tm_al:
                        for _t_al in _tm_al.group(1).split(','):
                            _t_al = _t_al.strip()
                            if _t_al:
                                _tc[_t_al] = _tc.get(_t_al, 0) + 1
                _banned_al = [t for t, n in _tc.items() if n >= 2 and t not in _COORD_MULTI_USE_OK]
