                        'send_outreach_email', 'send_email',
                        'check_emails', 'update_goal_progress', 'create_goal',
                        'get_news_trends',
                        'run_agent_action', 'publish_to_telegram', 'publish_to_discord',
                        'reply_to_outreach_email', 'send_follow_up_email',
